import { modelCostAdvisor } from '../../subagent-start/model-cost-advisor.js';
import { existsSync, readFileSync } from 'node:fs';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
const norm = (p: string): string => p.replace(/\\/g, '/');

function mkInput(subagent_type = 'test-agent', description = 'A test task'): HookInput {
  return { tool_name: 'Task', session_id: 'test-session-cost', tool_input: { subagent_type, description } };
}

function agentMd(model?: string, skills?: string[]): string {
  let fm = '---\n';
  if (model) fm += `model: ${model}\n`;
  if (skills) { fm += 'skills:\n'; for (const s of skills) fm += `  - ${s}\n`; }
  return `${fm}---\n\n## Directive\nDo something.\n`;
}

function skillMd(complexity: string): string {
  return `---\nname: test-skill\ncomplexity: ${complexity}\n---\n\n# Skill\n`;
}

function setupFs(cfg: {
  agentModel?: string; agentSkills?: string[];
  skillComplexities?: Record<string, string>;
  agentExists?: boolean;
}): void {
  (existsSync as ReturnType<typeof vi.fn>).mockImplementation((raw: string) => {
    if (typeof raw !== 'string') return false;
    const p = norm(raw);
    if (p.endsWith('.md') && p.includes('/agents/')) return cfg.agentExists !== false;
    if (p.includes('/skills/') && p.endsWith('SKILL.md')) {
      const name = p.split('/skills/')[1]?.split('/')[0];
      return name ? (cfg.skillComplexities?.[name] !== undefined) : false;
    }
    return false;
  });
  (readFileSync as ReturnType<typeof vi.fn>).mockImplementation((raw: string) => {
    if (typeof raw !== 'string') return '';
    const p = norm(raw);
    if (p.endsWith('.md') && p.includes('/agents/'))
      return agentMd(cfg.agentModel, cfg.agentSkills);
    if (p.includes('/skills/') && p.endsWith('SKILL.md')) {
      const name = p.split('/skills/')[1]?.split('/')[0];
      const c = name ? cfg.skillComplexities?.[name] : undefined;
      if (c) return skillMd(c);
    }
    return '';
  });
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------
describe('modelCostAdvisor', () => {
  const savedEnv = { ...process.env };

  beforeEach(() => {
    vi.clearAllMocks();
    process.env.CLAUDE_PROJECT_DIR = '/test/project';
    (existsSync as ReturnType<typeof vi.fn>).mockReturnValue(false);
    (readFileSync as ReturnType<typeof vi.fn>).mockReturnValue('');
  });

  afterEach(() => { process.env = { ...savedEnv }; });

  // 1. Early return
  describe('early return for missing agent type', () => {
    test('silentSuccess when subagent_type is empty', () => {
      const r = modelCostAdvisor(mkInput('', 'task'));
      expect(r.continue).toBe(true);
      expect(r.suppressOutput).toBe(true);
    });

    test('silentSuccess when tool_input has no subagent_type', () => {
      const r = modelCostAdvisor({ tool_name: 'Task', session_id: 's', tool_input: {} });
      expect(r.continue).toBe(true);
      expect(r.suppressOutput).toBe(true);
    });
  });

  // 2. No advice needed
  describe('no advice needed (model appropriate)', () => {
    test('sonnet for medium-complexity task', () => {
      setupFs({ agentModel: 'sonnet' });
      const r = modelCostAdvisor(mkInput('agent', 'implement a feature'));
      expect(r.continue).toBe(true);
      expect(r.suppressOutput).toBe(true);
    });

    test('opus for high-complexity task (explicit opus)', () => {
      setupFs({ agentModel: 'opus' });
      const r = modelCostAdvisor(mkInput('agent', 'security audit vulnerability penetration'));
      expect(r.continue).toBe(true);
      expect(r.suppressOutput).toBe(true);
    });

    test('haiku for low-complexity task', () => {
      setupFs({ agentModel: 'haiku' });
      const r = modelCostAdvisor(mkInput('agent', 'list files and check status summary'));
      expect(r.continue).toBe(true);
      expect(r.suppressOutput).toBe(true);
    });
  });

  // 3. Keyword complexity detection
  describe('complexity detection via keywords', () => {
    test.each([
      'security audit vulnerability scan',
      'architect distributed system design',
      'migration schema database design',
      'performance optimization profiling bottleneck',
    ])('HIGH complexity: "%s"', (desc) => {
      setupFs({ agentModel: 'haiku' });
      expect(modelCostAdvisor(mkInput('a', desc)).continue).toBe(true);
    });

    test.each([
      'list files and check status',
      'simple straightforward quick fix',
      'format lint style rename typo',
    ])('LOW complexity: "%s"', (desc) => {
      setupFs({ agentModel: 'opus' });
      expect(modelCostAdvisor(mkInput('a', desc)).continue).toBe(true);
    });

    test('defaults to medium when no keyword signals', () => {
      setupFs({ agentModel: 'sonnet' });
      const r = modelCostAdvisor(mkInput('a', 'implement the feature'));
      expect(r.continue).toBe(true);
      expect(r.suppressOutput).toBe(true);
    });
  });

  // 4. Skill frontmatter complexity
  describe('complexity from skill frontmatter', () => {
    test('uses highest skill complexity', () => {
      setupFs({
        agentModel: 'haiku',
        agentSkills: ['s1', 's2'],
        skillComplexities: { s1: 'low', s2: 'high' },
      });
      // high on haiku → upgrade advice (silent, savingsPercent=0)
      const r = modelCostAdvisor(mkInput('a', 'do something'));
      expect(r.continue).toBe(true);
    });

    test('skill high overrides low-keyword description', () => {
      setupFs({
        agentModel: 'haiku',
        agentSkills: ['cs'],
        skillComplexities: { cs: 'high' },
      });
      const r = modelCostAdvisor(mkInput('a', 'simple list check status'));
      expect(r.continue).toBe(true);
    });

    test('falls back to keywords when no skills in frontmatter', () => {
      setupFs({ agentModel: 'haiku' });
      const r = modelCostAdvisor(mkInput('a', 'security vulnerability audit penetration'));
      expect(r.continue).toBe(true);
    });
  });

  // 5. Downgrade recommendations
  describe('downgrade recommendations', () => {
    test('warns opus for low-complexity (40% savings)', () => {
      setupFs({ agentModel: 'opus' });
      const r = modelCostAdvisor(mkInput('a', 'list files check status summary'));
      expect(r.continue).toBe(true);
      if (r.hookSpecificOutput?.additionalContext) {
        expect(r.hookSpecificOutput.additionalContext).toContain('40%');
        expect(r.hookSpecificOutput.additionalContext).toContain('sonnet');
      }
    });

    test('warns inherited opus for medium-complexity (30% savings)', () => {
      setupFs({ agentExists: false });
      process.env.CLAUDE_MODEL = 'opus';
      const r = modelCostAdvisor(mkInput('a', 'implement a module'));
      expect(r.continue).toBe(true);
    });
  });

  // 6. Upgrade recommendations
  describe('upgrade recommendations', () => {
    test('advises upgrade for haiku on high-complexity (silent, 0% savings)', () => {
      setupFs({ agentModel: 'haiku' });
      const r = modelCostAdvisor(mkInput('a', 'security audit vulnerability penetration'));
      expect(r.continue).toBe(true);
      expect(r.suppressOutput).toBe(true);
    });
  });

  // 7. Inherit resolution
  describe('model resolution (inherit)', () => {
    test('resolves to CLAUDE_MODEL env var', () => {
      setupFs({ agentExists: false });
      process.env.CLAUDE_MODEL = 'haiku';
      const r = modelCostAdvisor(mkInput('a', 'security vulnerability audit penetration architect design'));
      expect(r.continue).toBe(true);
    });

    test('resolves to sonnet when CLAUDE_MODEL unset', () => {
      setupFs({ agentExists: false });
      delete process.env.CLAUDE_MODEL;
      const r = modelCostAdvisor(mkInput('a', 'implement feature'));
      expect(r.continue).toBe(true);
      expect(r.suppressOutput).toBe(true);
    });
  });

  // 8. Explicit vs inherited opus for medium task
  describe('explicit vs inherited opus (medium task)', () => {
    test('no advice when agent explicitly requires opus', () => {
      setupFs({ agentModel: 'opus' });
      const r = modelCostAdvisor(mkInput('a', 'implement a module'));
      expect(r.continue).toBe(true);
      expect(r.suppressOutput).toBe(true);
    });

    test('advises downgrade when opus is only inherited', () => {
      setupFs({ agentExists: false });
      process.env.CLAUDE_MODEL = 'opus';
      const r = modelCostAdvisor(mkInput('a', 'implement a module'));
      expect(r.continue).toBe(true);
    });
  });

  // 9. Edge cases
  describe('edge cases', () => {
    test('agent file with no frontmatter', () => {
      (existsSync as ReturnType<typeof vi.fn>).mockReturnValue(true);
      (readFileSync as ReturnType<typeof vi.fn>).mockReturnValue('# No frontmatter\n');
      expect(modelCostAdvisor(mkInput('a', 'task')).continue).toBe(true);
    });

    test('readFileSync error handled gracefully', () => {
      (existsSync as ReturnType<typeof vi.fn>).mockReturnValue(true);
      (readFileSync as ReturnType<typeof vi.fn>).mockImplementation(() => { throw new Error('EACCES'); });
      expect(() => modelCostAdvisor(mkInput('a', 'task'))).not.toThrow();
    });

    test('missing pluginRoot handled gracefully', () => {
      delete process.env.CLAUDE_PROJECT_DIR;
      delete process.env.CLAUDE_PLUGIN_ROOT;
      delete process.env.MCP_TOOL_NAME;
      expect(modelCostAdvisor(mkInput('a', 'task')).continue).toBe(true);
    });

    test('agent with skills but no SKILL.md files', () => {
      setupFs({ agentModel: 'sonnet', agentSkills: ['missing-1', 'missing-2'], skillComplexities: {} });
      expect(modelCostAdvisor(mkInput('a', 'task')).continue).toBe(true);
    });

    test('only scans first 5 skills (performance limit)', () => {
      const skills = Array.from({ length: 8 }, (_, i) => `s${i}`);
      const cx: Record<string, string> = {};
      for (const s of skills) cx[s] = 'low';
      cx.s7 = 'high'; // beyond 5-skill limit
      setupFs({ agentModel: 'sonnet', agentSkills: skills, skillComplexities: cx });
      expect(modelCostAdvisor(mkInput('a', 'task')).continue).toBe(true);
    });

    test('never blocks (continue always true)', () => {
      setupFs({ agentModel: 'opus' });
      const r = modelCostAdvisor(mkInput('a', 'simple list check status quick'));
      expect(r.continue).toBe(true);
    });
  });
});
